import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import './Header.css';

const Header = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isActive = (path) => location.pathname === path;

  const closeMobileMenu = () => {
    setIsMobileMenuOpen(false);
  };

  return (
    <header className={`header ${isScrolled ? 'scrolled' : ''}`}>
      <div className="container">
        <div className="header-content">
          <Link to="/" className="logo" onClick={closeMobileMenu}>
            <img src="/logo.png" alt="Greyline Accountants Ltd." className="logo-image" />
          </Link>

          <nav className={`nav ${isMobileMenuOpen ? 'open' : ''}`}>
            <Link to="/services" className={isActive('/services') ? 'active' : ''} onClick={closeMobileMenu}>
              Services
            </Link>
            <Link to="/blog" className={isActive('/blog') ? 'active' : ''} onClick={closeMobileMenu}>
              Insights
            </Link>
            <Link to="/contact" className={isActive('/contact') ? 'active' : ''} onClick={closeMobileMenu}>
              Contact
            </Link>
            <Link to="/contact" className="btn-primary" onClick={closeMobileMenu}>
              Schedule a Call
            </Link>
          </nav>

          <button 
            className="mobile-menu-toggle"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle menu"
          >
            <span></span>
            <span></span>
            <span></span>
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;
